"use strict";exports.id=378,exports.ids=[378],exports.modules={9378:a=>{a.exports=JSON.parse('{"meta":{"title":"WordPing — スマートに英語を学ぼう","description":"AI翻訳・美しいテーマ・毎日のリマインダーを備えた、本気で英語を学ぶ人のためのスマート単語帳アプリ。"},"nav":{"features":"機能","howItWorks":"使い方","download":"ダウンロード"},"hero":{"badge":"iOS版 好評配信中","title":"英語をマスター、\\n一語ずつ。","subtitle":"WordPingは、AI翻訳・美しいテーマ・毎日のリマインダーを備えたスマートな単語帳アプリです。本気で学ぶ人のために作られました。","ctaNote":"無料でダウンロード"},"features":{"badge":"機能","title":"学習に必要なすべてが揃う","subtitle":"シンプルなツールで、確実な成果を。","cards":{"flashcards":{"title":"スマートフラッシュカード","desc":"カードをスワイプして意味を確認。フォルダに整理して、自分のペースで学習できます。"},"ai":{"title":"AI自動翻訳","desc":"どんな単語でも即座にAIが文脈に応じた意味を生成。手動で調べる手間がなくなります。"},"test":{"title":"テストモード","desc":"単語並べ替え・穴埋め・テストで記憶を定着。挑戦しながら自然に身につきます。"},"notifications":{"title":"毎日のリマインダー","desc":"プッシュ通知で毎日の学習を習慣化。小さな積み重ねが大きな成果につながります。"},"themes":{"title":"美しいテーマ","desc":"Deep Sea・桜・Night Cityなど、プレミアムテーマで学習空間をカスタマイズ。"},"folders":{"title":"フォルダで整理","desc":"テーマや難易度ごとにフォルダで単語を管理。整理された環境で効率よく学習できます。"}}},"how":{"badge":"使い方","title":"3ステップで始められる","steps":{"1":{"title":"単語を追加する","desc":"覚えたい単語やフレーズを保存。意味・メモを追加してフォルダに整理しましょう。"},"2":{"title":"毎日学習する","desc":"カードをめくって確認し、テストを受け、通知で復習を習慣化。継続が上達への近道です。"},"3":{"title":"成長を実感する","desc":"単語を習得するにつれて語彙が豊かになっていきます。着実な進歩を体感しましょう。"}}},"cta":{"title":"今日から学習をはじめよう","subtitle":"無料ダウンロード。プレミアムテーマも利用可能。","button":"App Storeでダウンロード"},"footer":{"tagline":"本気で学ぶ人のために作られた。","rights":"\xa9 2025 WordPing. All rights reserved."}}')}};